const GROUP_FALLBACK = { fridge: "🥬", freezer: "🧊", sauce: "🧂", room: "🥫" };

// Longer keywords win (e.g. "양배추" before "배") so specific names beat substrings.
EMOJI_RULES.sort((a, b) => b[0].length - a[0].length);

function emojiFor(name, type) {
  for (const [kw, e] of EMOJI_RULES) if (name.includes(kw)) return e;
  return GROUP_FALLBACK[type] || "🍽️";
}

